    "creditCost": 0,
    "description": "[API] create",
    "name": "api_posts_create",
    "parameters": {
      "properties": {
        "campaign": {
          "type": "string",
          "description": "Optional campaign identifier. When provided with an empty ingredients array, the server resolves approved campaign image ingredients for the current brand."
        },
        "category": {
          "type": "string",
          "description": "Type of media being published (image or video) - automatically derived from ingredient if not provided"
        },
        "contentRunId": {
          "type": "string",
          "description": "Originating content run ID for closed-loop attribution"
        },
        "creativeVersion": {
          "type": "string",
          "description": "Creative revision or experiment version label"
        },
        "credential": {
          "type": "string",
          "description": "The credential ID (platform account) to use for publishing"
        },
        "description": {
          "type": "string",
          "description": "The description/caption for the post"
        },
        "externalId": {
          "type": "string",
          "description": "External platform ID for the published content"
        },
        "externalShortcode": {
          "type": "string",
          "description": "External platform shortcode for the published content"
        },
        "groupId": {
          "type": "string",
          "description": "Group ID for batch post notifications. Posts created together (multi-platform batch) share the same groupId."
        },
        "hookVersion": {
          "type": "string",
          "description": "Hook revision or experiment version label"
        },
        "ingredients": {
          "type": "array",
          "description": "Array of ingredient IDs (content) to be published. Order is preserved for carousels. Can be empty array for drafts. Max: 35 (TikTok limit).",
          "items": {
            "type": "string"
          }
        },
        "isAnalyticsEnabled": {
          "type": "boolean",
          "description": "Whether to fetch analytics for the post"
        },
        "isRepeat": {
          "type": "boolean",
          "description": "Whether this post should repeat on a schedule"
        },
        "isShareToFeedSelected": {
          "type": "boolean",
          "description": "For Instagram Reels only: whether to share the reel to main feed"
        },
        "label": {
          "type": "string",
          "description": "The title/label of the post"
        },
        "maxRepeats": {
          "type": "number",
          "description": "Maximum number of times to repeat (0 = unlimited)"
        },
        "order": {
          "type": "number",
          "description": "Position/order within thread"
        },
        "parent": {
          "type": "string",
          "description": "Parent post ID for thread replies"
        },
        "personaId": {
          "type": "string",
          "description": "Persona ID used to shape the published output"
        },
        "publicationDate": {
          "type": "string",
          "description": "When the post was actually posted"
        },
        "publishIntent": {
          "type": "string",
          "description": "High-level publish intent such as test, campaign, or evergreen"
        },
        "quoteTweetId": {
          "type": "string",
          "description": "Twitter-specific: ID of tweet to quote (creates a quote tweet)"
        },
        "repeatDaysOfWeek": {
          "type": "array",
          "description": "Days of week to repeat (0=Sunday, 6=Saturday)",
          "items": {
            "type": "number"
          }
        },
        "repeatEndDate": {
          "type": "string",
          "description": "When to stop repeating the post"
        },
        "repeatFrequency": {
          "type": "string",
          "description": "How often the post should repeat"
        },
        "repeatInterval": {
          "type": "number",
          "description": "The interval between repeats (e.g., every 2 days)"
        },
        "scheduleSlot": {
          "type": "string",
          "description": "Named schedule slot used for publish attribution"
        },
        "scheduledDate": {
          "type": "string",
          "description": "When the post is scheduled to be posted"
        },
        "source": {
          "type": "string",
          "description": "Origin label for the post (e.g. agent, fastlane, manual). Free-form string."
        },
        "status": {
          "type": "string",
          "description": "The current status of the post"
        },
        "tags": {
          "type": "array",
          "description": "Optional tags/hashtags to include with the post",
          "items": {
            "type": "string"
          }
        },
        "threadPosts": {
          "type": "array",
          "description": "Array of posts for batch thread creation",
          "items": {
            "type": "object"
          }
        },
        "timezone": {
          "type": "string",
          "description": "IANA timezone string for the scheduled date (e.g., \"America/New_York\", \"Europe/London\"). Defaults to UTC if not provided."
        },
        "variantId": {
          "type": "string",
          "description": "Originating variant ID inside the content run"
        }
      },
      "required": [
        "credential",
        "description",
        "ingredients",
        "status"
      ],
      "type": "object"
    },
    "requiredRole": "user",
